class User {
  constructor(id, name) {
    this.id = id;
    this.name = name;
  }
}

class Message {
  constructor(id, userId, content, timestamp) {
    this.id = id;
    this.userId = userId;
    this.content = content;
    this.timestamp = timestamp || new Date();
  }
}

class ChatModel {
  constructor() {
    this.users = new Map(); // Key: userId, Value: User object
    this.messages = [];
  }

  addUser(user) {
    this.users.set(user.id, user);
  }

  removeUser(userId) {
    this.users.delete(userId);
  }

  addMessage(message) {
    this.messages.push(message);
  }

  getMessages() {
    return this.messages;
  }

  getUser(userId) {
    return this.users.get(userId);
  }
}

const chat = new ChatModel();

// Adding users
const user1 = new User('u1', 'Alice');
const user2 = new User('u2', 'Bob');
chat.addUser(user1);
chat.addUser(user2);

// Adding messages
chat.addMessage(new Message('m1', 'u1', 'Hello Bob!'));
chat.addMessage(new Message('m2', 'u2', 'Hi Alice!'));

// Fetch messages
console.log(chat.getMessages());
// Fetch a user
console.log(chat.getUser('u1'));

const target = {};

const handler = {
  get(obj, prop) {
    if (!(prop in obj)) {
      console.error(`Property "${prop}" does not exist.`);
      return undefined;
    }
    return obj[prop];
  }
};

const proxy = new Proxy(target, handler);

console.log(proxy.name); // Logs error and returns undefined

const mathOperations = {
  divide(a, b) {
    return a / b;
  }
};

const handler = {
  get(target, prop) {
    const value = target[prop];
    if (typeof value === 'function') {
      return function(...args) {
        try {
          if (prop === 'divide' && args[1] === 0) {
            throw new Error('Cannot divide by zero');
          }
          return value.apply(this, args);
        } catch (error) {
          console.error(`Error in method "${prop}":`, error.message);
          return null;
        }
      };
    }
    return value;
  }
};

const proxyMath = new Proxy(mathOperations, handler);

console.log(proxyMath.divide(10, 2)); // 5
console.log(proxyMath.divide(10, 0)); // Logs error and returns null

const user = {
  name: 'Alice',
  age: 25
};

const handler = {
  set(obj, prop, value) {
    if (prop === 'age' && (typeof value !== 'number' || value < 0)) {
      console.error('Invalid age value:', value);
      return false; // Prevent assignment
    }
    obj[prop] = value;
    console.log(`Property "${prop}" set to ${value}`);
    return true;
  }
};

const proxyUser = new Proxy(user, handler);

proxyUser.age = 30; // Logs property set
proxyUser.age = -5; // Logs invalid age error
proxyUser.name = 'Bob'; // Logs property set

