type User = {
  id: number;
  name: string;
};

type Admin = {
  isAdmin: true;
  permissions: string[];
};

// Intersection of User and Admin

type AdminUser = User & Admin;

const adminUser: AdminUser = {
  id: 1,
  name: 'Alice',
  isAdmin: true,
  permissions: ['read', 'write', 'delete'],
};

console.log(adminUser);

type User = {
  id: number;
  name: string;
  email?: string;
};

// Make all properties required

type RequiredUser = {
  [K in keyof User]-?: User[K];
};

const user: RequiredUser = {
  id: 123,
  name: 'Bob',
  email: 'bob@example.com',
};

console.log(user);

function greet(name: string) {
  console.log(`Hello, ${name.toUpperCase()}!`);
}

greet(undefined); // Runtime error: Cannot read property 'toUpperCase' of undefined

function greet(name?: string) {
  console.log(`Hello, ${name?.toUpperCase() ?? 'Guest'}!`);
}

greet(undefined); // Prints: Hello, Guest!

function greet(name: string | null | undefined) {
  if (name) {
    console.log(`Hello, ${name.toUpperCase()}!`);
  } else {
    console.log('Hello, Guest!');
  }
}

greet(null);    // Hello, Guest!
greet('Alice'); // Hello, Alice!

function greet(name: string = 'Guest') {
  console.log(`Hello, ${name.toUpperCase()}!`);
}

greet();        // Hello, Guest!
greet('Bob');   // Hello, Bob!

interface User {
  name?: string | null;
}

function getUserName(user: User) {
  return user.name?.toUpperCase() ?? 'UNKNOWN';
}

const user1 = { name: 'Jane' };
const user2 = { name: null };
const user3 = {};

console.log(getUserName(user1)); // JANE
console.log(getUserName(user2)); // UNKNOWN
console.log(getUserName(user3)); // UNKNOWN

